function parseKvMap(raw) {
  const map = new Map();
  for (const item of String(raw || '').split(',')) {
    const [left, right] = item.split('=', 2);
    const key = left?.trim();
    const value = right?.trim();
    if (key && value) map.set(key, value);
  }
  return map;
}

